import json

result_lines = []

income_items = [
    ("consulting", 5000, "Client payment: consulting work"),
    ("product_sales", 1500, "Product sale"),
    ("referral_income", 500, "Referral bonus"),
]

expense_items = [
    ("software_subscriptions", 299, "Software subscriptions"),
    ("marketing_ads", 800, "Marketing ads"),
    ("professional_development", 450, "Professional development"),
    ("business_lunch", 125, "Business lunch"),
]

created = {"income": [], "expenses": []}

for category, amount, description in income_items:
    resp = json.loads(tools.create_transaction(
        transaction_type="income",
        category=category,
        amount=amount,
        description=description,
        account="checking"
    ))
    if resp.get("error"):
        result = "Error creating income transaction (%s, $%s): %s" % (category, amount, resp["error"])
        break
    created["income"].append(resp["transaction"])

else:
    for category, amount, description in expense_items:
        resp = json.loads(tools.create_transaction(
            transaction_type="expense",
            category=category,
            amount=amount,
            description=description,
            account="checking"
        ))
        if resp.get("error"):
            result = "Error creating expense transaction (%s, $%s): %s" % (category, amount, resp["error"])
            break
        created["expenses"].append(resp["transaction"])
    else:
        summary_resp = json.loads(tools.get_financial_summary())
        if summary_resp.get("error"):
            result = "Error fetching financial summary: %s" % summary_resp["error"]
        else:
            s = summary_resp["summary"]
            checking_balance_resp = json.loads(tools.get_account_balance("checking"))
            if checking_balance_resp.get("error"):
                result = "Error fetching checking balance: %s" % checking_balance_resp["error"]
            else:
                income_by_cat = s.get("income_by_category", {}) or {}
                expense_by_cat = s.get("expense_by_category", {}) or {}

                result_lines.append("Financial Summary")
                result_lines.append("")
                result_lines.append("Total income by category:")
                if income_by_cat:
                    for k in sorted(income_by_cat.keys()):
                        result_lines.append(f"- {k}: ${income_by_cat[k]:,.2f}")
                else:
                    result_lines.append("- (none)")

                result_lines.append("")
                result_lines.append("Total expenses by category:")
                if expense_by_cat:
                    for k in sorted(expense_by_cat.keys()):
                        result_lines.append(f"- {k}: ${expense_by_cat[k]:,.2f}")
                else:
                    result_lines.append("- (none)")

                result_lines.append("")
                result_lines.append(f"Net income (income - expenses): ${s.get('net_income', 0.0):,.2f}")
                result_lines.append(f"Current checking account balance: ${checking_balance_resp['balance']:,.2f}")

                result = "\n".join(result_lines)

