        # RetailCo mark paid (tool may record remaining payment income automatically)
        if "result" not in globals():
            inv = invoice_by_client.get("RetailCo")
            if inv:
                resp = json.loads(tools.update_invoice_status(inv["id"], "paid"))
                if "error" in resp:
                    result = "Error marking RetailCo invoice as paid: %s" % resp["error"]
                else:
                    payment_actions.append(resp)
                    invoice_by_client["RetailCo"] = resp["invoice"]

        # TechGiant partial payment $10,000
        if "result" not in globals():
            inv = invoice_by_client.get("TechGiant")
            if inv:
                resp = json.loads(tools.record_partial_payment(inv["id"], 10000))
                if "error" in resp:
                    result = "Error recording partial payment for TechGiant: %s" % resp["error"]
                else:
                    payment_actions.append(resp)
                    invoice_by_client["TechGiant"] = resp["invoice"]

        if "result" not in globals():
            # 4) Reporting
            inv_resp = json.loads(tools.get_invoices())
            if "error" in inv_resp:
                result = "Error fetching invoices: %s" % inv_resp["error"]
            else:
                invoices = inv_resp["invoices"]

                state_resp = json.loads(tools.get_state_summary())
                if "error" in state_resp:
                    result = "Error fetching state summary: %s" % state_resp["error"]
                else:
                    summary = state_resp["summary"]
                    outstanding = float(summary.get("outstanding_receivables", 0.0))
                    total_income = float(summary.get("total_income", 0.0))

                    # Follow-up: any invoice not paid (sent/partial/etc.)
                    follow_up = []
                    invoice_lines = []
                    for inv in invoices:
                        total = float(inv.get("amount", 0.0))
                        paid = float(inv.get("paid_amount", 0.0))
                        remaining = total - paid
                        status = inv.get("status", "unknown")
                        invoice_lines.append(
                            " - %s (ID %s): status=%s | total=$%.2f | paid=$%.2f | remaining=$%.2f | due=%s"
                            % (inv.get("client_name", ""), inv.get("id", ""), status, total, paid, remaining, inv.get("due_date", ""))
                        )
                        if status != "paid" and remaining > 0:
                            follow_up.append("%s (ID %s): status=%s, remaining=$%.2f, due=%s" % (
                                inv.get("client_name", ""), inv.get("id", ""), status, remaining, inv.get("due_date", "")
                            ))

                    result_lines.append("INVOICE REPORT")
                    result_lines.append("")
                    result_lines.append("All invoices (status, totals):")
                    result_lines.extend(invoice_lines)
                    result_lines.append("")
                    result_lines.append("Totals:")
                    result_lines.append(" - Total outstanding receivables: $%.2f" % outstanding)
                    result_lines.append(" - Total payments received (income): $%.2f" % total_income)
                    result_lines.append("")
                    result_lines.append("Invoices needing follow-up:")
                    if follow_up:
                        for line in follow_up:
                            result_lines.append(" - " + line)
                    else:
                        result_lines.append(" - None")

                    result = "\n".join(result_lines)

